import React, {useRef, useState, useEffect} from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import SingleOrderSection from '../components/SingleOrderSection'
import {} from '../WebAPI.js'


const ShoppingCartWrapper = styled.div `
display:flex;
width:80%;
margin:60px auto;
justify-content:space-between;
align-items:center;
`

const ItemsPart = styled.div `
width:700px;
`

const InfoPart = styled.div `
width:400px;
display:flex;
justify-content:center;
flex-direction:column;
`

const ItemsWrapper = styled.div `
display:flex;
flex-direction:column;
width:100%;
`


const OrderTotalInfo = styled.div `
height:60px;
width:100%;
padding:30px 0;
padding-left:100px;
box-sizing:border-box;
`

const OrderDetail =styled.div `
display:flex;
justify-content:space-between;
`

const Detail = styled.div `
font-size:0.7rem;
`

const OrderTotalDetail = styled(OrderDetail) `
font-weight:900;
`

const ShippingAdressWrapper = styled.div `
display:flex;
flex-direction:column
`

const Title = styled.div `
font-size:0.9rem;
font-weight:900;
`

const Adress = styled.pre `

`

export default function ShoppingCart () {

	return (
		<>
			<Header />
			<Navbar />
			<ShoppingCartWrapper>
				<ItemsPart>
					<ItemsWrapper>
						<SingleOrderSection/>
						<OrderTotalInfo>
							<OrderDetail>
								<Detail>Total</Detail>
								<Detail>30000</Detail>
							</OrderDetail>
							<OrderDetail>
								<Detail>Duties & Taxes</Detail>
								<Detail>300</Detail>
							</OrderDetail>
							<OrderTotalDetail>
								<Detail>Order Total</Detail>
								<Detail>30300</Detail>
							</OrderTotalDetail>
						</OrderTotalInfo>
					</ItemsWrapper>
				</ItemsPart>
				<InfoPart>
					<ShippingAdressWrapper>
						<Title>Shipping Adress</Title>
						<Adress>
						Yang bin Hong
						</Adress>
					</ShippingAdressWrapper>
					<ShippingAdressWrapper>
						<Title>Payment Method</Title>
					</ShippingAdressWrapper>
				</InfoPart>
			</ShoppingCartWrapper>
		</>	
	)
}
